/// <summary>
/// The <c>ETGForexReportsDP</c> class is the report data provider class for Vendor, customer and GL related forex data like Unrealized/ realized
/// </summary>
[SrsReportParameterAttribute(classStr(ETGForexReportsContract))]
class ETGForexReportsDP extends SRSReportDataProviderBase
{
    ETGForexReportsTmp          forexReportsTmp;
    ETGForexReportsContract     contract;
    FromDate                    fromDate;
    ToDate                      toDate;
    ETGForexType                forexType;
    VendTrans                   vendTrans,VendTransloc;
    CustTrans                   custTrans,custTransloc;
    CustSettlement              custSettlement,custSettlementloc,custSettlementpervios,custSettlementexh,custSettlementorig;
    VendSettlement              vendSettlement,vendSettlementloc,vendSettlementpervios,vendSettlementexh,VendSettlementorig;
    LedgerTransSettlement       ledgerTransSettlement, ledgerTransSettlement2,ledgerTransSettlement3,ledgerTransSettlement4,ledgerTransSettlement5, ledgerTransSettlement6, ledgerTransSettlement7, ledgerTransSettlement8,ledgerTransSettlement9;
    GeneralJournalAccountEntry  gjAE,gjAE2;
    GeneralJournalEntry         gje,gje2;
    LedgerTransSettlementView   ledgerTransSettlementView;
    Ledger      ledger = Ledger::find(Ledger::current()) ;
    MainAccount                 mainAccount;

    ExchangeRate     exchangeRate;
    ExchangeRateType ExchangeRateType;
    ExchangeRateCurrencyPair exchangeRateCurrencyPair;
    real             exchRate,exchRatepervios;


}

Method.Source:
/// <summary>
/// Executes temporary table.
/// </summary>
/// <returns>
/// The data for the report in the <c>forexReportsTmp</c> table.
/// </returns>
[
    SRSReportDataSetAttribute(tablestr(ETGForexReportsTmp))
]
public ETGForexReportsTmp getForexreportsTmp()
{
    select forexReportsTmp;
    return forexReportsTmp;
}

/// <summary>
/// Process the business logic.
/// </summary>
public void processReport()
{
    ETGModuleType   moduleType;
    contract = this.parmDataContract() as  ETGForexReportsContract;

    moduleType          = contract.parmModuleType();
    fromDate            = contract.parmFromDate();
    toDate              = contract.parmToDate();
    forexType           = contract.parmForexType();

    forexReportsTmp.CompanyLogo  = FormLetter::companyLogo(); //Inserting company logo

    if(moduleType == ETGModuleType::Vendor && forexType == ETGForexType::Both)
    {
        this.getUnrealizedVend();
        this.getRealizedVend();

    }
    //When module type is vendor and forex type is unrealized
    else  if(moduleType == ETGModuleType::Vendor && forexType == ETGForexType::Unrealised)
    {
        this.getUnrealizedVend();
    }
    //When module type is vendor and forex type is realised
    else  if(moduleType == ETGModuleType::Vendor && forexType == ETGForexType::Realised)
    {
        this.getRealizedVend();
    }
    if(moduleType == ETGModuleType::Customer && forexType == ETGForexType::Both)
    {
        this.getUnrealizedCust();
        this.getrealizedCust();

    }
    //When module type is customer and forex type is unrealized
    else  if(moduleType == ETGModuleType::Customer && forexType == ETGForexType::Unrealised)
    {
        this.getUnrealizedCust();
    }
    //When module type is customer and forex type is unrealized
    else  if(moduleType == ETGModuleType::Customer && forexType == ETGForexType::Realised)
    {
        this.getrealizedCust();
    }
    else if(moduleType == ETGModuleType::GeneralLedger && forexType == ETGForexType::Both)
    {
        this.getRealizedLedger();
        this.getUnRealizedLedger();
        //As Unrealzed is not given in the requiremrnt

    }
    else if(moduleType == ETGModuleType::GeneralLedger && forexType == ETGForexType::Realised)
    {
        this.getRealizedLedger();
    }
    else if(moduleType == ETGModuleType::GeneralLedger && forexType == ETGForexType::Unrealised)
    {
        this.getUnRealizedLedger();
    }
    else if(moduleType == ETGModuleType::ALL && forexType == ETGForexType::Both)
    {
        this.getUnrealizedVend();
        this.getRealizedVend();
        this.getUnrealizedCust();
        this.getrealizedCust();
        this.getRealizedLedger();
        this.getUnRealizedLedger();
    }
    else if(moduleType == ETGModuleType::ALL && forexType == ETGForexType::Unrealised)
    {
        this.getUnrealizedVend();
        this.getUnrealizedCust();
        this.getUnRealizedLedger();

    }
    else if(moduleType == ETGModuleType::ALL && forexType == ETGForexType::Realised)
    {
        this.getRealizedVend();
        this.getrealizedCust();
        this.getRealizedLedger();
    }

}

/// <summary>
/// Gets the dimenion values
/// </summary>
public void getDefaultDimensionValue(RefRecId  _defaultDimension)
{
    DefaultDimensionView        defaultDimesnionView;

    while select DisplayValue,Name from defaultDimesnionView
        where defaultDimesnionView.DefaultDimension == _defaultDimension
            && defaultDimesnionView.Name  == '@ETG_New:MainCommodity'

    {
        if(defaultDimesnionView.Name  == '@ETG_New:MainCommodity')
        forexReportsTmp.MainCommodity = defaultDimesnionView.DisplayValue;
    }
}

